reference_solution:
def safe_max(nums):
    if not nums:
        return None
    best = nums[0]
    for n in nums[1:]:
        if n > best:
            best = n
    return best

def is_palindrome(text):
    normalized = text.lower()
    return normalized == normalized[::-1]

